-- ============================================================================
-- UTAH FAB DIRECTORY — Complete Supabase Setup
-- This script is IDEMPOTENT — safe to re-run at any time.
-- Paste the entire contents into Supabase Dashboard > SQL Editor > New Query
-- ============================================================================


-- ============================================================================
-- PHASE 1: NUCLEAR CLEANUP — Drop ALL function overloads
-- ============================================================================
-- Dynamically finds and drops EVERY overload of every managed function,
-- regardless of parameter types. No stale versions survive this.
-- ============================================================================

DO $$
DECLARE
  _rec RECORD;
BEGIN
  -- List every managed function name here:
  FOR _rec IN
    SELECT p.oid::regprocedure AS func_signature
    FROM   pg_proc p
    JOIN   pg_namespace n ON n.oid = p.pronamespace
    WHERE  n.nspname = 'public'
      AND  p.proname IN (
             'update_modified_column'
           )
  LOOP
    EXECUTE 'DROP FUNCTION IF EXISTS ' || _rec.func_signature || ' CASCADE';
    RAISE NOTICE 'Dropped function: %', _rec.func_signature;
  END LOOP;
END
$$;


-- ============================================================================
-- PHASE 2: TABLES — Create or verify structure
-- ============================================================================
-- Uses IF NOT EXISTS so existing data is never destroyed.
-- To alter columns on an existing install, add explicit ALTER TABLE blocks.
-- ============================================================================

-- 2a. Regions lookup
CREATE TABLE IF NOT EXISTS regions (
  slug        TEXT PRIMARY KEY,
  title       TEXT NOT NULL,
  subtitle    TEXT DEFAULT '',
  sort_order  INT  NOT NULL DEFAULT 0
);

-- 2b. Core table: fab_shops
CREATE TABLE IF NOT EXISTS fab_shops (
  id           UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  name         TEXT NOT NULL,
  region       TEXT NOT NULL REFERENCES regions(slug),
  city         TEXT NOT NULL DEFAULT '',
  category     TEXT NOT NULL DEFAULT 'Fabrication & Machining',
  size_desc    TEXT DEFAULT '',
  services     TEXT DEFAULT '',
  notable_desc TEXT DEFAULT '',
  website      TEXT DEFAULT '',
  maps_url     TEXT DEFAULT '',
  tags         TEXT[] DEFAULT '{}',
  is_notable   BOOLEAN DEFAULT false,
  is_active    BOOLEAN DEFAULT true,
  sort_order   INT DEFAULT 0,
  created_at   TIMESTAMPTZ DEFAULT now(),
  updated_at   TIMESTAMPTZ DEFAULT now()
);

-- 2c. Analytics table (optional)
CREATE TABLE IF NOT EXISTS directory_analytics (
  id          BIGINT GENERATED ALWAYS AS IDENTITY PRIMARY KEY,
  event_type  TEXT NOT NULL,
  event_value TEXT DEFAULT '',
  metadata    JSONB DEFAULT '{}',
  created_at  TIMESTAMPTZ DEFAULT now()
);


-- ============================================================================
-- PHASE 3: INDEXES — Idempotent with IF NOT EXISTS
-- ============================================================================

-- Add maps_url column if it doesn't already exist (for existing installs)
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns
    WHERE table_name = 'fab_shops' AND column_name = 'maps_url'
  ) THEN
    ALTER TABLE fab_shops ADD COLUMN maps_url TEXT DEFAULT '';
  END IF;
END
$$;

CREATE INDEX IF NOT EXISTS idx_fab_shops_region   ON fab_shops(region);
CREATE INDEX IF NOT EXISTS idx_fab_shops_active   ON fab_shops(is_active);
CREATE INDEX IF NOT EXISTS idx_fab_shops_tags     ON fab_shops USING GIN(tags);
CREATE INDEX IF NOT EXISTS idx_fab_shops_notable  ON fab_shops(is_notable) WHERE is_notable = true;
CREATE INDEX IF NOT EXISTS idx_analytics_type     ON directory_analytics(event_type);
CREATE INDEX IF NOT EXISTS idx_analytics_time     ON directory_analytics(created_at);


-- ============================================================================
-- PHASE 4: FUNCTIONS & TRIGGERS — Recreated fresh every run
-- ============================================================================
-- Phase 1 already dropped all overloads; now recreate cleanly.
-- ============================================================================

CREATE OR REPLACE FUNCTION update_modified_column()
RETURNS TRIGGER AS $$
BEGIN
  NEW.updated_at = now();
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

DROP TRIGGER IF EXISTS set_updated_at ON fab_shops;
CREATE TRIGGER set_updated_at
  BEFORE UPDATE ON fab_shops
  FOR EACH ROW
  EXECUTE FUNCTION update_modified_column();


-- ============================================================================
-- PHASE 5: ROW LEVEL SECURITY — Drop-then-create for clean idempotency
-- ============================================================================

ALTER TABLE fab_shops             ENABLE ROW LEVEL SECURITY;
ALTER TABLE regions               ENABLE ROW LEVEL SECURITY;
ALTER TABLE directory_analytics   ENABLE ROW LEVEL SECURITY;

-- fab_shops policies
DROP POLICY IF EXISTS "Public read active shops"  ON fab_shops;
DROP POLICY IF EXISTS "Admin full access shops"   ON fab_shops;

CREATE POLICY "Public read active shops"
  ON fab_shops FOR SELECT
  USING (is_active = true);

CREATE POLICY "Admin full access shops"
  ON fab_shops FOR ALL
  USING (auth.role() = 'authenticated')
  WITH CHECK (auth.role() = 'authenticated');

-- regions policies
DROP POLICY IF EXISTS "Public read regions"        ON regions;
DROP POLICY IF EXISTS "Admin full access regions"   ON regions;

CREATE POLICY "Public read regions"
  ON regions FOR SELECT
  USING (true);

CREATE POLICY "Admin full access regions"
  ON regions FOR ALL
  USING (auth.role() = 'authenticated')
  WITH CHECK (auth.role() = 'authenticated');

-- analytics policies
DROP POLICY IF EXISTS "Anon insert analytics"      ON directory_analytics;
DROP POLICY IF EXISTS "Admin read analytics"       ON directory_analytics;

-- ⚠️  Consider a rate-limit function or pg_cron cleanup job in production
--    to prevent abuse of unrestricted anonymous inserts.
CREATE POLICY "Anon insert analytics"
  ON directory_analytics FOR INSERT
  WITH CHECK (true);

CREATE POLICY "Admin read analytics"
  ON directory_analytics FOR SELECT
  USING (auth.role() = 'authenticated');


-- ============================================================================
-- PHASE 5b: STORAGE — contact-photos bucket
-- ============================================================================
-- NOTE: metadata fields (mimetype, size) are populated AFTER insert, so
-- checking them in WITH CHECK causes RLS to reject all uploads.
-- File-type and size validation is enforced in script.js instead.
-- ============================================================================

VALUES ('contact-photos', 'contact-photos', true)
ON CONFLICT (id) DO NOTHING;

DROP POLICY IF EXISTS "Anon upload contact photos" ON storage.objects;
CREATE POLICY "Anon upload contact photos"
  ON storage.objects FOR INSERT
  TO public
  WITH CHECK (bucket_id = 'contact-photos');

DROP POLICY IF EXISTS "Public read contact photos" ON storage.objects;
CREATE POLICY "Public read contact photos"
  ON storage.objects FOR SELECT
  TO public
  USING (bucket_id = 'contact-photos');


-- ============================================================================
-- PHASE 6: SEED DATA — Regions (upsert)
-- ============================================================================

ON CONFLICT (slug) DO UPDATE SET
  title      = EXCLUDED.title,
  subtitle   = EXCLUDED.subtitle,
  sort_order = EXCLUDED.sort_order;


-- ============================================================================
-- PHASE 7: SEED DATA — Shops (upsert on name + region)
-- ============================================================================
-- Uses a unique constraint on (name, region) for safe re-runs.
-- If the shop already exists, every column is refreshed.
-- ============================================================================

DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint WHERE conname = 'uq_fab_shops_name_region'
  ) THEN
    ALTER TABLE fab_shops ADD CONSTRAINT uq_fab_shops_name_region UNIQUE (name, region);
  END IF;
END
$$;

ON CONFLICT ON CONSTRAINT uq_fab_shops_name_region DO UPDATE SET
  city         = EXCLUDED.city,
  category     = EXCLUDED.category,
  size_desc    = EXCLUDED.size_desc,
  services     = EXCLUDED.services,
  notable_desc = EXCLUDED.notable_desc,
  website      = EXCLUDED.website,
  maps_url     = EXCLUDED.maps_url,
  tags         = EXCLUDED.tags,
  is_notable   = EXCLUDED.is_notable,
  is_active    = EXCLUDED.is_active,
  sort_order   = EXCLUDED.sort_order;


-- ============================================================================
-- DONE — Verify counts
-- ============================================================================
DO $$
DECLARE
  _regions INT;
  _shops   INT;
BEGIN
  SELECT count(*) INTO _regions FROM regions;
  SELECT count(*) INTO _shops   FROM fab_shops;
  RAISE NOTICE '== SETUP COMPLETE ==  Regions: %  |  Shops: %', _regions, _shops;
END
$$;

